		if err := row.Columns(&columnName, &optionValue); err != nil {
			return err
		}
		columns[columnName] = strings.EqualFold(strings.TrimSpace(optionValue), "TRUE")
		return nil
	}); err != nil {
		return nil, err
	}

	return columns, nil
}

