645	func detectGoModuleConfig(startDir string) (modulePath, langVersion string) {
646		dir, err := filepath.Abs(startDir)
647		if err != nil {
648			dir = startDir
649		}
650	
651		for dir != "" {
652			data, err := os.ReadFile(filepath.Join(dir, "go.mod"))
653			if err == nil {
654				return parseGoModMetadata(data)
655			}
656	
657			parent := filepath.Dir(dir)
658			if parent == dir {
659				break
660			}
661			dir = parent
662		}
663	
664		return "", ""
665	}
