667	func parseGoModMetadata(data []byte) (modulePath, langVersion string) {
668		for line := range strings.SplitSeq(string(data), "\n") {
669			fields := strings.Fields(strings.TrimSpace(line))
670			if len(fields) < 2 {
671				continue
672			}
673	
674			switch fields[0] {
675			case "module":
676				if modulePath == "" {
677					modulePath = strings.Trim(fields[1], "\"")
678				}
679			case "go":
680				if langVersion == "" {
681					langVersion = "go" + fields[1]
682				}
683			}
684	
685			if modulePath != "" && langVersion != "" {
686				break
687			}
688		}
689	
690		return modulePath, langVersion
691	}
